const agenda = $node["Definir Agenda"].json;
const eventosRaw = $items("Disponibilidade do Google Calendar").map(item => item.json);
const trigger = $node["trigger"].json || {};

const tz = agenda.timezone || "America/Sao_Paulo";
const intervaloMin = agenda.timeBetweenMeetingsMinutes;
const diasSemana = { DOM: 0, SEG: 1, TER: 2, QUA: 3, QUI: 4, SEX: 5, SAB: 6 };

// Normaliza eventos: pega só YYYY-MM-DDTHH:MM
const eventos = (eventosRaw || [])
  .filter(ev => ev?.start?.dateTime && ev?.end?.dateTime)
  .map(ev => ({
    start: ev.start.dateTime.substring(0, 16),
    end:   ev.end.dateTime.substring(0, 16),
  }));

// -------------------------
// Datas relativas (SP)
// -------------------------

function getDataOffset(dias) {
  const hojeLocalStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0, 10);
  const d = new Date(hojeLocalStr + "T00:00:00Z");
  d.setUTCDate(d.getUTCDate() + dias);
  return d.toISOString().slice(0, 10);
}

const hojeStr = getDataOffset(0);
const amanhaStr = getDataOffset(1);
const depoisAmanhaStr = getDataOffset(2);

const agoraSP = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(11, 16);

// -------------------------
// Próxima data para o dia da semana
// -------------------------

function getProximaData(diaNome) {
  const hojeLocalStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0, 10);
  let cursor = new Date(hojeLocalStr + "T00:00:00Z");
  let tentativas = 0;

  while (cursor.getUTCDay() !== diasSemana[diaNome]) {
    cursor.setUTCDate(cursor.getUTCDate() + 1);
    if (++tentativas > 7) break;
  }

  return cursor.toISOString().slice(0, 10);
}

// -------------------------
// Helpers
// -------------------------

function somaMinutos(hhmm, min) {
  const [h, m] = hhmm.split(":").map(Number);
  const total = h * 60 + m + min;
  return String(Math.floor(total / 60)).padStart(2, "0") + ":" + String(total % 60).padStart(2, "0");
}

function menorQue(a, b) {
  return a < b;
}

// -------------------------
// Geração dos Slots
// -------------------------

let slotsLivres = [];

for (const dia of agenda.schedule) {
  if (!dia.available) continue;

  const dataStr = getProximaData(dia.day);
  const faixas = Array.isArray(dia.hours) ? dia.hours : [dia.hours];

  for (const faixa of faixas) {
    let current = faixa.after;
    const fim = faixa.before;

    while (menorQue(current, fim)) {
      const next = somaMinutos(current, intervaloMin);

      if (!menorQue(next, fim) && next !== fim) break;
      if (next > fim) break;

      const currentDT = `${dataStr}T${current}`;
      const nextDT = `${dataStr}T${next}`;

      // Bloqueia slots passados de hoje (+30 min margem)
      if (dataStr === hojeStr) {
        const limite = somaMinutos(agoraSP, 30);
        if (menorQue(current, limite)) {
          current = next;
          continue;
        }
      }

      const ocupado = eventos.some(ev => currentDT < ev.end && nextDT > ev.start);

      if (!ocupado) {

        let relative = null;

        if (dataStr === hojeStr) {
          relative = "hoje";
        } else if (dataStr === amanhaStr) {
          relative = "amanha";
        } else if (dataStr === depoisAmanhaStr) {
          relative = "depois_amanha";
        }

        slotsLivres.push({
          day: dia.day,
          date: dataStr,
          start: currentDT,
          end: nextDT,
          relativeDay: relative,
          isToday: dataStr === hojeStr,
          isTomorrow: dataStr === amanhaStr,
          isDayAfterTomorrow: dataStr === depoisAmanhaStr
        });
      }

      current = next;
    }
  }
}

// -------------------------
// 🔎 Validação COMPLETA do horário solicitado
// -------------------------

let horarioSolicitadoDisponivel = null;
let motivoIndisponivel = null;

if (trigger.horario) {

  // -------------------------
  // 🔎 Normaliza horário solicitado
  // -------------------------

  let inicioSolicitado = null;

  if (trigger.horario.includes("T")) {
    // Formato completo: 2026-03-05T19:00
    inicioSolicitado = trigger.horario.substring(0, 16);
  } else if (trigger.dia) {
    // Formato separado: dia + horario
    inicioSolicitado = `${trigger.dia}T${trigger.horario}`;
  }

  if (!inicioSolicitado) {
    horarioSolicitadoDisponivel = null;
  } else {

    const dataSolicitada = inicioSolicitado.slice(0, 10);
    const horaSolicitada = inicioSolicitado.slice(11);

  const fimSolicitado = dataSolicitada + "T" +
    somaMinutos(horaSolicitada, intervaloMin);

  // 1️⃣ Verifica se o dia existe na agenda
  const dataObj = new Date(dataSolicitada + "T00:00:00");
  const diaSemanaNumero = dataObj.getDay();

  const diaAgenda = agenda.schedule.find(d =>
    diasSemana[d.day] === diaSemanaNumero
  );

  if (!diaAgenda || !diaAgenda.available) {
    horarioSolicitadoDisponivel = false;
    motivoIndisponivel = "dia_nao_disponivel";
  } else {

    const faixas = Array.isArray(diaAgenda.hours)
      ? diaAgenda.hours
      : [diaAgenda.hours];

    // 2️⃣ Verifica se está dentro de alguma faixa permitida
    const dentroDeAlgumaFaixa = faixas.some(faixa => {
      return horaSolicitada >= faixa.after &&
             somaMinutos(horaSolicitada, intervaloMin) <= faixa.before;
    });

    if (!dentroDeAlgumaFaixa) {
      horarioSolicitadoDisponivel = false;
      motivoIndisponivel = "fora_do_horario";
    } else {

      // 3️⃣ Verifica conflito com eventos
      const ocupado = eventos.some(ev =>
        inicioSolicitado < ev.end && fimSolicitado > ev.start
      );

      if (ocupado) {
        horarioSolicitadoDisponivel = false;
        motivoIndisponivel = "conflito_evento";
      } else {

        // 4️⃣ Verifica se é horário passado (regra hoje +30min)
        if (dataSolicitada === hojeStr) {
          const limite = somaMinutos(agoraSP, 30);
          if (horaSolicitada < limite) {
            horarioSolicitadoDisponivel = false;
            motivoIndisponivel = "horario_passado";
          } else {
            horarioSolicitadoDisponivel = true;
          }
        } else {
          horarioSolicitadoDisponivel = true;
        }

      }
    }
  }
}
}

// Ordena slots pela data/hora real
slotsLivres.sort((a, b) => new Date(a.start) - new Date(b.start));
// -------------------------
// Output final
// -------------------------

return [{
  slotsLivres,
  horarioSolicitado: trigger.horario || null,
  horarioSolicitadoDisponivel
}];

const agenda = $node["Definir Agenda"].json;
const eventosRaw = $items("Obter Eventos do Google Calendar").map(item => item.json);

const tz = agenda.timezone || "America/Sao_Paulo";
const intervaloMin = agenda.timeBetweenMeetingsMinutes;
const diasSemana = { DOM: 0, SEG: 1, TER: 2, QUA: 3, QUI: 4, SEX: 5, SAB: 6 };

// Normaliza eventos: pega só YYYY-MM-DDTHH:MM do dateTime de SP
const eventos = (eventosRaw || [])
  .filter(ev => ev?.start?.dateTime && ev?.end?.dateTime)
  .map(ev => ({
    // dateTime vem como "2026-02-23T10:00:00-03:00" → pega só "2026-02-23T10:00"
    start: ev.start.dateTime.substring(0, 16),
    end:   ev.end.dateTime.substring(0, 16),
  }));

// "Hoje" em SP
const hojeStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0, 10);
const agoraSP = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(11, 16); // "HH:MM"

// Próxima data para um dia da semana, calculada em SP
function getProximaData(diaNome) {
  const hojeLocalStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0, 10);
  let cursor = new Date(hojeLocalStr + "T00:00:00Z");
  let tentativas = 0;
  while (cursor.getUTCDay() !== diasSemana[diaNome]) {
    cursor.setUTCDate(cursor.getUTCDate() + 1);
    if (++tentativas > 7) break;
  }
  return cursor.toISOString().slice(0, 10); // "YYYY-MM-DD"
}

// Soma minutos em "HH:MM"
function somaMinutos(hhmm, min) {
  const [h, m] = hhmm.split(":").map(Number);
  const total = h * 60 + m + min;
  return String(Math.floor(total / 60)).padStart(2, "0") + ":" + String(total % 60).padStart(2, "0");
}

// Compara "HH:MM" como string
function menorQue(a, b) {
  return a < b;
}

let slotsLivres = [];

for (const dia of agenda.schedule) {
  if (!dia.available) continue;

  const dataStr = getProximaData(dia.day); // "YYYY-MM-DD" em SP
  const faixas = Array.isArray(dia.hours) ? dia.hours : [dia.hours];

  for (const faixa of faixas) {
    let current = faixa.after;   // "HH:MM"
    const fim   = faixa.before;  // "HH:MM"

    while (menorQue(current, fim)) {
      const next = somaMinutos(current, intervaloMin);
      if (!menorQue(next, fim) && next !== fim) break;
      if (next > fim) break;

      const currentDT = `${dataStr}T${current}`; // "YYYY-MM-DDTHH:MM"
      const nextDT    = `${dataStr}T${next}`;

      // Bloqueia slots passados de hoje (+ 30 min de margem)
      if (dataStr === hojeStr) {
        const limite = somaMinutos(agoraSP, 30);
        if (menorQue(current, limite)) {
          current = next;
          continue;
        }
      }

      // Checa conflito: compara strings "YYYY-MM-DDTHH:MM" diretamente
      const ocupado = eventos.some(ev => currentDT < ev.end && nextDT > ev.start);

      if (!ocupado) {
        slotsLivres.push({
          day:   dia.day,
          start: currentDT,  // "2026-02-23T11:00" — SP, sem Z, sem conversão
          end:   nextDT,
        });
      }

      current = next;
    }
  }
}

return slotsLivres;

// ===============================
// INPUT
// ===============================
const input = $items("trigger")[0].json;
const { dia, horario, nome, empresa, email, telefone, descricao } = input;

const tz = "America/Sao_Paulo";

// ===============================
// DATA ATUAL EM SP
// ===============================
const agora = new Date().toLocaleString("sv-SE", { timeZone: tz });
const hojeStr = agora.slice(0, 10);
const agoraSP = agora.slice(11, 16);

function somaMinutos(hhmm, min) {
  const [h, m] = hhmm.split(":").map(Number);
  const total = h * 60 + m + min;
  return String(Math.floor(total / 60)).padStart(2, "0") + ":" +
         String(total % 60).padStart(2, "0");
}

const limite = somaMinutos(agoraSP, 30);

// ===============================
// PEGAR TODOS OS SLOTS (FORMATO REAL)
// ===============================
const slotsBase = $items("Gerar Slots Livres").map(item => item.json);

if (!slotsBase.length) {
  throw new Error("Nenhum slot retornado pelo node 'Gerar Slots Livres'.");
}

// ===============================
// FILTRAR PASSADO E < 30 MIN
// ===============================
const slots = slotsBase.filter(slot => {
  const slotDia  = slot.start.slice(0, 10);
  const slotHora = slot.start.slice(11, 16);

  if (slotDia === hojeStr) return slotHora >= limite;
  return slotDia > hojeStr;
});

// ===============================
// VERIFICAR HORÁRIO SOLICITADO
// ===============================
let solicitadoKey;

if (horario.includes("T")) {
  solicitadoKey = horario.slice(0, 16);
} else {
  solicitadoKey = `${dia}T${horario}`;
}
const encontrado = slots.find(slot => slot.start === solicitadoKey);

if (encontrado) {
  return [{
    json: {
      status: "ok",
      message: `Horário disponível: ${dia} ${horario}. Pode agendar.`,
      dados: {
        nome,
        empresa,
        email,
        telefone,
        descricao,
        inicio: { dateTime: `${encontrado.start}:00`, timeZone: tz },
        fim:    { dateTime: `${encontrado.end}:00`,   timeZone: tz }
      }
    }
  }];
}

// ===============================
// AGRUPAR POR DIA
// ===============================
const slotsPorDia = {};

for (const slot of slots) {
  const d = slot.start.slice(0, 10);
  if (!slotsPorDia[d]) slotsPorDia[d] = [];
  slotsPorDia[d].push(slot);
}

for (const d in slotsPorDia) {
  slotsPorDia[d].sort((a, b) => a.start.localeCompare(b.start));
}

// ===============================
// FUNÇÃO PARA SOMAR DIAS
// ===============================
function addDias(dataStr, n) {
  const d = new Date(dataStr + "T00:00:00Z");
  d.setUTCDate(d.getUTCDate() + n);
  return d.toISOString().slice(0, 10);
}

// ===============================
// BUSCAR ALTERNATIVAS
// ===============================
let alternativas = [];

const prev = addDias(dia, -1);
const next = addDias(dia, +1);

alternativas.push(...(slotsPorDia[prev]?.slice(0, 2) || []));
alternativas.push(...(slotsPorDia[dia]?.slice(0, 2)  || []));
alternativas.push(...(slotsPorDia[next]?.slice(0, 2) || []));

let offset = 2;

while (alternativas.length < 2 && offset <= 7) {
  alternativas.push(...(slotsPorDia[addDias(dia, -offset)]?.slice(0, 2) || []));
  alternativas.push(...(slotsPorDia[addDias(dia, +offset)]?.slice(0, 2) || []));
  offset++;
}

alternativas = alternativas
  .slice(0, 6)
  .map(slot => ({
    inicio: { dateTime: `${slot.start}:00`, timeZone: tz },
    fim:    { dateTime: `${slot.end}:00`,   timeZone: tz }
  }));

// ===============================
// RETORNO INDISPONÍVEL
// ===============================
return [{
  json: {
    status: "indisponivel",
    message: `O horário ${dia} ${horario} não está disponível.`,
    alternativas
  }
}];

