={{
  (() => {
    let raw = $('trigger').first().json.telefone || "";

    // só números
    let num = raw.toString().replace(/\D/g, "");

    // remove zeros iniciais
    num = num.replace(/^0+/, "");

    // garante prefixo 55
    if (!num.startsWith("55")) {
      num = "55" + num;
    }

    // se tiver 12 dígitos: 55 + DDD + número sem 9
    if (num.length === 12) {
      const pais = num.slice(0, 2);
      const ddd  = num.slice(2, 4);
      const base = num.slice(4);    // 8 dígitos
      num = pais + ddd + "9" + base;
    }

    // se passar de 13 dígitos, pega os últimos 13
    if (num.length > 13) {
      num = num.slice(-13);
    }

    // retorna no formato 5511XXXXXXXXX (sem +)
    return num;
  })()
}}

