const leadEmail = $('trigger').item.json.email ? $('trigger').item.json.email.trim().toLowerCase() : '';
const now = new Date();

// 1. Filtra eventos onde o lead está presente
const matches = items.filter(item => {
  const event = item.json;
  if (event.attendees && Array.isArray(event.attendees)) {
    return event.attendees.some(attendee => 
      attendee.email && attendee.email.trim().toLowerCase() === leadEmail
    );
  }
  return false;
});

// 2. Filtra apenas eventos futuros e ordena por data
const futureMeetings = matches
  .filter(item => new Date(item.json.start.dateTime) > now) // Apenas datas futuras
  .sort((a, b) => new Date(a.json.start.dateTime) - new Date(b.json.start.dateTime)); // Ordena do mais próximo para o mais distante

// Retorna a reunião futura mais próxima. Se não houver futura, retorna a última encontrada.
return futureMeetings.length > 0 ? [futureMeetings[0]] : matches;

const TIMEZONE = "America/Sao_Paulo";

const leadEmailRaw = $('trigger').first().json.email; 

if (!leadEmailRaw) {
    return [{ json: { error: "Dados incompletos", found: false } }];
}

const leadEmail = leadEmailRaw.trim().toLowerCase();

// Use UTC mesmo (mais seguro)
const now = new Date();

// Função pra pegar dateTime com fallback (caso seja all-day)
function getEventDate(item) {
  const start = item.json.start;
  if (!start) return null;

  // Eventos com hora
  if (start.dateTime) return new Date(start.dateTime);

  // Eventos all-day (date)
  if (start.date) return new Date(start.date + "T00:00:00");

  return null;
}

// Filtra eventos do lead
const matches = items.filter(item => {
  const event = item.json;

  return event.attendees?.some(attendee =>
    attendee.email?.trim().toLowerCase() === leadEmail
  );
});

// Separa eventos futuros e passados
const futureMeetings = matches
  .map(item => ({ item, date: getEventDate(item) }))
  .filter(e => e.date && e.date >= now)
  .sort((a, b) => a.date - b.date);

const pastMeetings = matches
  .map(item => ({ item, date: getEventDate(item) }))
  .filter(e => e.date && e.date < now)
  .sort((a, b) => b.date - a.date);

// Pega os candidatos
const nextMeeting = futureMeetings[0] || null;
const lastMeeting = pastMeetings[0] || null;

// Formatação correta com timezone
function formatDateTime(date) {
  return {
    date: date.toLocaleDateString("pt-BR", {
      timeZone: TIMEZONE
    }),
    time: date.toLocaleTimeString("pt-BR", {
      timeZone: TIMEZONE,
      hour: '2-digit',
      minute: '2-digit'
    })
  };
}

return [{
  json: {
    found: !!(nextMeeting || lastMeeting),

    nextMeeting: nextMeeting ? {
      eventId: nextMeeting.item.json.id,
      summary: nextMeeting.item.json.summary,
      ...formatDateTime(nextMeeting.date)
    } : null,

    lastMeeting: lastMeeting ? {
      eventId: lastMeeting.item.json.id,
      summary: lastMeeting.item.json.summary,
      ...formatDateTime(lastMeeting.date)
    } : null
  }
}];

const TIMEZONE_OFFSET = '-03:00'; 
const MEETING_DURATION_MINUTES = 30;

const leadEmailRaw = $('trigger').item.json.email; 
const newDateStr = $('trigger').item.json.dia;
const newTimeStr = $('trigger').item.json.horario;

if (!leadEmailRaw || !newDateStr || !newTimeStr) {
    return [{ json: { error: "Dados incompletos", found: false } }];
}

const leadEmail = leadEmailRaw.trim().toLowerCase();
const nowBrasil = new Date(new Date().toLocaleString("en-US", { timeZone: "America/Sao_Paulo" }));

const matches = items.filter(item => {
  const event = item.json;
  if (event.attendees && Array.isArray(event.attendees)) {
    return event.attendees.some(attendee => 
      attendee.email && attendee.email.trim().toLowerCase() === leadEmail
    );
  }
  return false;
});

// Pega o mais próximo de hoje, passado ou futuro
const meetingsSorted = matches
  .filter(item => item.json.start.dateTime)
  .sort((a, b) => {
    const diffA = Math.abs(new Date(a.json.start.dateTime) - nowBrasil);
    const diffB = Math.abs(new Date(b.json.start.dateTime) - nowBrasil);
    return diffA - diffB;
  });

if (meetingsSorted.length === 0) {
    return [{ json: { error: "Nenhuma reunião encontrada para reagendar.", found: false } }];
}

const meetingToReschedule = meetingsSorted[0];

const isoStringBrasil = `${newDateStr}T${newTimeStr}:00${TIMEZONE_OFFSET}`;
const startDate = new Date(isoStringBrasil);
const endDate = new Date(startDate.getTime() + MEETING_DURATION_MINUTES * 60000);

return [{
    json: {
        found: true,
        eventId: meetingToReschedule.json.id,
        calendarId: "primary",
        summary: meetingToReschedule.json.summary,
        updatePayload: {
            start: {
                dateTime: startDate.toISOString(), 
                timeZone: "America/Sao_Paulo"
            },
            end: {
                dateTime: endDate.toISOString(),
                timeZone: "America/Sao_Paulo"
            }
        },
        debug_check: `Entrada: ${isoStringBrasil} -> Gerado UTC: ${startDate.toISOString()}`
    }
}];

