const TIMEZONE_OFFSET = '-03:00';
const MEETING_DURATION_MINUTES = 30;

const leadEmailRaw = $('trigger').first().json.email;
const newDateStr = $('trigger').first().json.dia;
const newTimeStr = $('trigger').first().json.horario;

const eventos = $items("Obter Eventos do Google Calendar").map(e => e.json);

if (!leadEmailRaw || !newDateStr || !newTimeStr) {
  return [{ json: { error: "Dados incompletos" } }];
}

const leadEmail = leadEmailRaw.trim().toLowerCase();

const nowBrasil = new Date(new Date().toLocaleString("en-US", { timeZone: "America/Sao_Paulo" }));

// ===========================================================
// 1️⃣ FILTRAR EVENTOS DO LEAD
// ===========================================================
const matches = eventos.filter(event => {
  if (!event.attendees) return false;
  return event.attendees.some(att =>
    att.email && att.email.trim().toLowerCase() === leadEmail
  );
});

// Pega a mais próxima de hoje, passada ou futura
const meetingsSorted = matches
  .filter(ev => ev.start.dateTime)
  .sort((a, b) => {
    const diffA = Math.abs(new Date(a.start.dateTime) - nowBrasil);
    const diffB = Math.abs(new Date(b.start.dateTime) - nowBrasil);
    return diffA - diffB; // menor diferença primeiro
  });

// ===========================================================
// 2️⃣ DEFINIR SE É REAGENDAMENTO
// ===========================================================
let isReschedule = false;
let meetingToReschedule = null;

if (meetingsSorted.length > 0) {
  isReschedule = true;
  meetingToReschedule = meetingsSorted[0];
}

// ===========================================================
// 3️⃣ CALCULAR NOVO HORÁRIO
// ===========================================================
const isoStringBrasil = `${newDateStr}T${newTimeStr}:00${TIMEZONE_OFFSET}`;
const startDate = new Date(isoStringBrasil);
const endDate = new Date(startDate.getTime() + MEETING_DURATION_MINUTES * 60000);

// ===========================================================
// 4️⃣ RETORNO
// ===========================================================
return [{
  json: {
    input: $input.all(),
    isReschedule,
    eventId: meetingToReschedule ? meetingToReschedule.id : null,
    summary: meetingToReschedule ? meetingToReschedule.summary : null,
    payload: {
      start: {
        dateTime: startDate.toISOString(),
        timeZone: "America/Sao_Paulo"
      },
      end: {
        dateTime: endDate.toISOString(),
        timeZone: "America/Sao_Paulo"
      }
    },
    debug: {
      entrada: isoStringBrasil,
      startUTC: startDate.toISOString(),
      leadEmail
    }
  }
}];
